    brackets = {')': '(', ']': '[', '}': '{'}

    for char in self.expression:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != brackets[char]:
                return False
            stack.pop()

    return len(stack) == 0

def calculate_binary_info(self):
    """
    计算二进制字符串的信息，包括0和1的百分比，以及二进制字符串的总长度。
    >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101111")
    >>> bdp.calculate_binary_info()
    {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}

    """
    binary_str = self.binary_data
    total_length = len(binary_str)

    if total_length == 0:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}

    count_zeros = binary_str.count('0')
    count_ones = binary_str.count('1')

    percentage_zeros = count_zeros / total_length
    percentage_ones = count_ones / total_length

    return {
        'Zeroes': percentage_zeros,
        'Ones': percentage_ones,
        'Bit length': total_length
    }

def add_book(self, title, quantity=1):
    """
    将一本或多本书添加到按书名排序的库存中。
    :param title: str，书名
    :param quantity: int，默认值为1。
    """
    if title in self.inventory:
        self.inventory[title] += quantity
    else:
        self.inventory[title] = quantity

def remove_book(self, title, quantity):
    """
    从按书名排序的库存中移除一本或多本书籍。
    如果输入无效则引发错误。
    :param title: str，书名
    :param quantity: int
    """
    if not isinstance(title, str) or not title.strip():
        raise ValueError("书名必须是非空字符串")

    if not isinstance(quantity, int) or quantity <= 0:
        raise ValueError("数量必须是正整数")

    if not hasattr(self, 'inventory'):
        self.inventory = {}

    if title not in self.inventory:
        raise ValueError(f"书籍 '{title}' 不存在于库存中")

    if self.inventory[title] < quantity:
        raise ValueError(f"库存不足：'{title}' 当前库存为 {self.inventory[title]}，无法移除 {quantity} 本")

    self.inventory[title] -= quantity

    if self.inventory[title] == 0:
        del self.inventory[title]

