    """
    从 cookies_file 加载 cookies 到 cookies 数据中。
    :return: cookies 数据，dict。
    >>> cookies_util = CookiesUtil('cookies.json')
    >>> cookies_util.load_cookies()
    {'key1': 'value1', 'key2': 'value2'}

    """
    import json
    import os

    # 如果文件不存在，返回空字典
    if not os.path.exists(self.cookies_file):
        self.cookies = {}
        return self.cookies

    # 从文件加载 cookies
