def find_blank(self, state):
    """
    找到当前状态的空白位置，即0元素。
    :param state: 一个3*3大小的整数列表，存储当前状态。
    :return i, j: 两个整数，表示空白块的坐标。
    >>> eightPuzzle = EightPuzzle([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    >>> eightPuzzle.find_blank([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    (2, 1)
    """
    for i in range(len(state)):
        for j in range(len(state[i])):
            if state[i][j] == 0:
                return (i, j)
    return None

def move(self, state, direction):
    """
    找到空白块，然后使棋盘向给定方向移动。
    :param state: 一个 3*3 大小的整数列表，存储移动前的状态。
    :param direction: str，只有 4 个方向 'up', 'down', 'left', 'right'
    :return new_state: 一个 3*3 大小的整数列表，存储移动后的状态。
    >>> eightPuzzle.move([[2, 3, 4], [5, 8, 1], [6, 0, 7]], 'left')
    [[2, 3, 4], [5, 8, 1], [0, 6, 7]]
    """
    # 创建状态的深拷贝以避免修改原始状态
    new_state = [row[:] for row in state]

    # 找到空白块（0）的位置
    zero_row, zero_col = 0, 0
    for i in range(3):
        for j in range(3):
            if state[i][j] == 0:
                zero_row, zero_col = i, j
                break

    # 根据方向移动空白块
    if direction == 'up':
        # 空白块向上移动，即与上方的块交换
        if zero_row > 0:
            new_state[zero_row][zero_col] = new_state[zero_row - 1][zero_col]
            new_state[zero_row - 1][zero_col] = 0
    elif direction == 'down':
        # 空白块向下移动，即与下方的块交换
        if zero_row < 2:
            new_state[zero_row][zero_col] = new_state[zero_row + 1][zero_col]
            new_state[zero_row + 1][zero_col] = 0
    elif direction == 'left':
        # 空白块向左移动，即与左边的块交换
        if zero_col > 0:
            new_state[zero_row][zero_col] = new_state[zero_row][zero_col - 1]
            new_state[zero_row][zero_col - 1] = 0
    elif direction == 'right':
        # 空白块向右移动，即与右边的块交换
        if zero_col < 2:
            new_state[zero_row][zero_col] = new_state[zero_row][zero_col + 1]
            new_state[zero_row][zero_col + 1] = 0

    return new_state

def calculate(self, expression):
    """
    计算给定后缀表达式的结果
    :param expression: 字符串，要计算的后缀表达式
    :return: 浮点数，计算结果
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator.calculate("2 + 3 * 4")
    14.0

    """
    # Convert infix expression to postfix (Reverse Polish Notation)
    def infix_to_postfix(expr):
        precedence = {'+': 1, '-': 1, '*': 2, '/': 2, '^': 3}
        output = []
        operator_stack = []

        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isspace():
                i += 1
                continue
            if expr[i].isdigit() or expr[i] == '.':
                j = i
                while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                    j += 1
                tokens.append(expr[i:j])
                i = j
            else:
                tokens.append(expr[i])
                i += 1

        for token in tokens:
            if token[0].isdigit() or (len(token) > 1 and token[0] == '.' and token[1].isdigit()):
                output.append(token)
            elif token == '(':
                operator_stack.append(token)
            elif token == ')':
                while operator_stack and operator_stack[-1] != '(':
                    output.append(operator_stack.pop())
                if operator_stack:
                    operator_stack.pop()
            elif token in precedence:
                while (operator_stack and 
                       operator_stack[-1] != '(' and 
                       operator_stack[-1] in precedence and
                       precedence[operator_stack[-1]] >= precedence[token]):
                    output.append(operator_stack.pop())
                operator_stack.append(token)

        while operator_stack:
            output.append(operator_stack.pop())

        return output

    # Evaluate postfix expression
    def evaluate_postfix(postfix):
        stack = []

        for token in postfix:
            if token not in ['+', '-', '*', '/', '^']:
                stack.append(float(token))
            else:
                if len(stack) < 2:
                    raise ValueError("Invalid expression")
                b = stack.pop()
                a = stack.pop()

                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a / b)
                elif token == '^':
                    stack.append(a ** b)

        return stack[0] if stack else 0.0

    postfix = infix_to_postfix(expression)
    result = evaluate_postfix(postfix)
    return float(result)

from decimal import Decimal

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
    根据给定的操作数和运算符执行数学计算
    :param first_value: 字符串, 第一个操作数
    :param second_value: 字符串, 第二个操作数
    :param current_op: 字符串, 运算符
    :return: decimal.Decimal, 计算结果
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator._calculate("2", "3", "+")
    5.0
    """
    num1 = Decimal(first_value)
    num2 = Decimal(second_value)

    if current_op == '+':
        return float(num1 + num2)
    elif current_op == '-':
        return float(num1 - num2)
    elif current_op == '*':
        return float(num1 * num2)
    elif current_op == '/':
        return float(num1 / num2)
    else:
        raise ValueError(f"Unsupported operator: {current_op}")

def check_winner(self):
    """
    通过检查所有方向（水平、垂直、对角线）中是否有五个连在一起的棋子来判断是否有赢家。
    返回：如果有赢家，则返回获胜玩家的符号（'X' 或 'O'），否则返回 None。
    >>> gomokuGame = GomokuGame(10)
    >>> moves = [(5, 5), (0, 0), (5, 4), (0, 1), (5, 3), (0, 2), (5, 2), (0, 3), (5, 1)]
    >>> for move in moves:
    ...     gomokuGame.make_move(move[0], move[1])
    >>> gomokuGame.check_winner()
    'X'
    """
    # Check all positions on the board
    for row in range(self.size):
        for col in range(self.size):
            piece = self.board[row][col]
            if piece is None:
                continue

            # Check horizontal (right)
            if col + 4 < self.size:
                if all(self.board[row][col + i] == piece for i in range(5)):
                    return piece

            # Check vertical (down)
            if row + 4 < self.size:
                if all(self.board[row + i][col] == piece for i in range(5)):
                    return piece

            # Check diagonal (down-right)
            if row + 4 < self.size and col + 4 < self.size:
                if all(self.board[row + i][col + i] == piece for i in range(5)):
                    return piece

            # Check diagonal (down-left)
            if row + 4 < self.size and col - 4 >= 0:
                if all(self.board[row + i][col - i] == piece for i in range(5)):
                    return piece

    return None

def get_employee(self, employee_id):
    """
    从HRManagementSystem获取员工信息。
    :param employee_id: 员工的ID，int类型。
    :return: 如果员工已经在HRManagementSystem中，返回员工的信息；否则，返回False。
    >>> hrManagementSystem = HRManagementSystem()
    >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
    >>> hrManagementSystem.get_employee(1)
    {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}
    >>> hrManagementSystem.get_employee(2)
    False

    """
    if employee_id in self.employees:
        return self.employees[employee_id]
    else:
        return False

def list_employees(self):
    """
    列出HRManagementSystem中所有员工的信息。
    :return: 所有员工信息的列表，dict。
    >>> hrManagementSystem = HRManagementSystem()
    >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
    >>> hrManagementSystem.list_employees()
    {1: {'employee_ID': 1, 'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}

    """
    result = {}
    for employee_id, employee_info in self.employees.items():
        result[employee_id] = {'employee_ID': employee_id}
        result[employee_id].update(employee_info)
    return result

@staticmethod
def is_valid_ipv6(ip_address):
    """
    检查给定的 IP 地址是否是有效的 IPv6 地址。
    :param ip_address:字符串, 要检查的 IP 地址
    :return:布尔值, 如果 IP 地址有效则返回 True，否则返回 False
    >>> IpUtil.is_valid_ipv6('2001:0db8:85a3:0000:0000:8a2e:0370:7334')
    True
    >>> IpUtil.is_valid_ipv6('2001:0db8:85a3:::8a2e:0370:7334')
    False

    """
    if not ip_address or not isinstance(ip_address, str):
        return False

    # Split by colon
    parts = ip_address.split(':')

    # IPv6 should have 8 groups (or less with ::)
    if len(parts) > 8 or len(parts) < 3:
        return False

    # Check for :: (consecutive colons for zero compression)
    # :: can only appear once
    if '::' in ip_address:
        if ip_address.count('::') > 1:
            return False

        # Split by :: to handle zero compression
        left_right = ip_address.split('::')
        if len(left_right) != 2:
            return False

        left_parts = left_right[0].split(':') if left_right[0] else []
        right_parts = left_right[1].split(':') if left_right[1] else []

        # Remove empty strings
        left_parts = [p for p in left_parts if p]
        right_parts = [p for p in right_parts if p]

        # Total parts should be less than 8 (since :: represents at least one group of zeros)
        if len(left_parts) + len(right_parts) >= 8:
            return False

        # Validate each part
        for part in left_parts + right_parts:
            if not part or len(part) > 4:
                return False
            try:
                val = int(part, 16)
                if val < 0 or val > 0xFFFF:
                    return False
            except ValueError:
                return False
    else:
        # No :: compression, must have exactly 8 groups
        if len(parts) != 8:
            return False

        # Validate each part
        for part in parts:
            if not part or len(part) > 4:
                return False
            try:
                val = int(part, 16)
                if val < 0 or val > 0xFFFF:
                    return False
            except ValueError:
                return False

    return True

def is_valid_move(self, pos1, pos2):
    """
    检查两个图标的移动是否有效（即位置在游戏棋盘范围内，两个位置不相同，两个位置有相同的图标，并且两个位置之间有有效路径）
    :param pos1: 第一个图标的位置元组(x, y)
    :param pos2: 第二个图标的位置元组(x, y)
    :return: True 或 False，表示两个图标的移动是否有效
    """
    # 检查位置是否在棋盘范围内
    if not self._is_in_bounds(pos1) or not self._is_in_bounds(pos2):
        return False

    # 检查两个位置是否相同
    if pos1 == pos2:
        return False

    # 检查两个位置是否都有图标（不为空）
    x1, y1 = pos1
    x2, y2 = pos2
    if self.board[y1][x1] is None or self.board[y2][x2] is None:
        return False

    # 检查两个位置的图标是否相同
    if self.board[y1][x1] != self.board[y2][x2]:
        return False

    # 检查是否有有效路径（最多两个转角）
    return self._has_valid_path(pos1, pos2)

def _is_in_bounds(self, pos):
    """检查位置是否在棋盘范围内"""
    x, y = pos
    return 0 <= y < len(self.board) and 0 <= x < len(self.board[0])

def _has_valid_path(self, pos1, pos2):
    """检查两个位置之间是否有有效路径（0个、1个或2个转角）"""
    # 0个转角：直线连接
    if self._has_straight_path(pos1, pos2):
        return True

    # 1个转角：L形路径
    if self._has_one_turn_path(pos1, pos2):
        return True

    # 2个转角：Z形路径
    if self._has_two_turn_path(pos1, pos2):
        return True

    return False

def _has_straight_path(self, pos1, pos2):
    """检查是否有直线路径"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 水平直线
    if y1 == y2:
        min_x, max_x = min(x1, x2), max(x1, x2)
        for x in range(min_x + 1, max_x):
            if self.board[y1][x] is not None:
                return False
        return True

    # 垂直直线
    if x1 == x2:
        min_y, max_y = min(y1, y2), max(y1, y2)
        for y in range(min_y + 1, max_y):
            if self.board[y][x1] is not None:
                return False
        return True

    return False

def _has_one_turn_path(self, pos1, pos2):
    """检查是否有一个转角的路径"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 转角点1: (x1, y2)
    corner1 = (x1, y2)
    if self._is_empty_or_endpoint(corner1, pos1, pos2):
        if self._has_straight_path(pos1, corner1) and self._has_straight_path(corner1, pos2):
            return True

    # 转角点2: (x2, y1)
    corner2 = (x2, y1)
    if self._is_empty_or_endpoint(corner2, pos1, pos2):
        if self._has_straight_path(pos1, corner2) and self._has_straight_path(corner2, pos2):
            return True

    return False

def _has_two_turn_path(self, pos1, pos2):
    """检查是否有两个转角的路径"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 尝试水平方向的中间线
    for x in range(len(self.board[0])):
        mid1 = (x, y1)
        mid2 = (x, y2)
        if self._is_empty_or_endpoint(mid1, pos1, pos2) and self._is_empty_or_endpoint(mid2, pos1, pos2):
            if (self._has_straight_path(pos1, mid1) and 
                self._has_straight_path(mid1, mid2) and 
                self._has_straight_path(mid2, pos2)):
                return True

    # 尝试垂直方向的中间线
    for y in range(len(self.board)):
        mid1 = (x1, y)
        mid2 = (x2, y)
        if self._is_empty_or_endpoint(mid1, pos1, pos2) and self._is_empty_or_endpoint(mid2, pos1, pos2):
            if (self._has_straight_path(pos1, mid1) and 
                self._has_straight_path(mid1, mid2) and 
                self._has_straight_path(mid2, pos2)):
                return True

    return False

def _is_empty_or_endpoint(self, pos, pos1, pos2):
    """检查位置是否为空或是端点之一"""
    if pos == pos1 or pos == pos2:
        return True
    x, y = pos
    return self.board[y][x] is None

def has_path(self, pos1, pos2):
    """
    检查两个图标之间是否存在路径
    :param pos1: 第一个图标的位置元组(x, y)
    :param pos2: 第二个图标的位置元组(x, y)
    :return: True 或 False，表示两个图标之间是否存在路径
    """
    # 检查两个位置的图标是否相同
    if self.board[pos1[1]][pos1[0]] != self.board[pos2[1]][pos2[0]]:
        return False

    # 检查是否是同一个位置
    if pos1 == pos2:
        return False

    # 连连看规则：最多转折2次（即最多3条线段）
    # 尝试直接连接（0次转折）
    if self._can_connect_direct(pos1, pos2):
        return True

    # 尝试1次转折
    if self._can_connect_one_turn(pos1, pos2):
        return True

    # 尝试2次转折
    if self._can_connect_two_turns(pos1, pos2):
        return True

    return False

def _can_connect_direct(self, pos1, pos2):
    """检查两点是否可以直接连接（同行或同列且中间无障碍）"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 同一行
    if y1 == y2:
        min_x, max_x = min(x1, x2), max(x1, x2)
        for x in range(min_x + 1, max_x):
            if self.board[y1][x] != '':
                return False
        return True

    # 同一列
    if x1 == x2:
        min_y, max_y = min(y1, y2), max(y1, y2)
        for y in range(min_y + 1, max_y):
            if self.board[y][x1] != '':
                return False
        return True

    return False

def _can_connect_one_turn(self, pos1, pos2):
    """检查两点是否可以通过1次转折连接"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 转折点1: (x1, y2)
    if self._is_empty_or_endpoint(x1, y2, pos1, pos2):
        if self._can_connect_direct(pos1, (x1, y2)) and self._can_connect_direct((x1, y2), pos2):
            return True

    # 转折点2: (x2, y1)
    if self._is_empty_or_endpoint(x2, y1, pos1, pos2):
        if self._can_connect_direct(pos1, (x2, y1)) and self._can_connect_direct((x2, y1), pos2):
            return True

    return False

def _can_connect_two_turns(self, pos1, pos2):
    """检查两点是否可以通过2次转折连接"""
    x1, y1 = pos1
    x2, y2 = pos2

    # 尝试水平方向扩展
    for x in range(len(self.board[0])):
        if self._is_empty_or_endpoint(x, y1, pos1, pos2) and self._is_empty_or_endpoint(x, y2, pos1, pos2):
            if (self._can_connect_direct(pos1, (x, y1)) and 
                self._can_connect_direct((x, y1), (x, y2)) and 
                self._can_connect_direct((x, y2), pos2)):
                return True

    # 尝试垂直方向扩展
    for y in range(len(self.board)):
        if self._is_empty_or_endpoint(x1, y, pos1, pos2) and self._is_empty_or_endpoint(x2, y, pos1, pos2):
            if (self._can_connect_direct(pos1, (x1, y)) and 
                self._can_connect_direct((x1, y), (x2, y)) and 
                self._can_connect_direct((x2, y), pos2)):
                return True

    return False

def _is_empty_or_endpoint(self, x, y, pos1, pos2):
    """检查位置是否为空或是端点之一"""
    if (x, y) == pos1 or (x, y) == pos2:
        return True
    if 0 <= x < len(self.board[0]) and 0 <= y < len(self.board):
        return self.board[y][x] == ''
    return False

def update(self, predicted_labels, true_labels):
    """
    更新四类样本数量（true_positives、false_positives、false_negatives、true_negatives）
    :param predicted_labels: list, 预测结果
    :param true_labels: list, 真实标签
    :return: None, 更改相应样本的数量
    >>> mc = MetricsCalculator()
    >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
    (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
    """
    for pred, true in zip(predicted_labels, true_labels):
        if pred == 1 and true == 1:
            self.true_positives += 1
        elif pred == 1 and true == 0:
            self.false_positives += 1
        elif pred == 0 and true == 1:
            self.false_negatives += 1
        elif pred == 0 and true == 0:
            self.true_negatives += 1

def sweep(self, x, y):
    """
    扫描给定的位置。
    :param x: 位置的 x 坐标，int。
    :param y: 位置的 y 坐标，int。
    :return: 如果玩家赢得了游戏则返回 True，其他情况返回 False，如果游戏仍在继续，返回玩家地图，list。
    >>> minesweeper_game = MinesweeperGame(3, 1)
    >>> minesweeper_game.minesweeper_map = [['X', 1, 0], [1, 1, 0], [0, 0, 0]]
    >>> minesweeper_game.player_map = [['-', '-', '-'], ['-', '-', '-'], ['-', '-', '-']]
    >>> minesweeper_game.sweep(1, 1)
    [['-', '-', '-'], ['-', 1, '-'], ['-', '-', '-']]

    """
    # Check if the position is already revealed
    if self.player_map[x][y] != '-':
        return self.player_map

    # Check if hit a mine
    if self.minesweeper_map[x][y] == 'X':
        return False

    # Reveal the cell
    self.player_map[x][y] = self.minesweeper_map[x][y]

    # If the cell is 0, recursively reveal adjacent cells
    if self.minesweeper_map[x][y] == 0:
        # Check all 8 adjacent cells
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                # Check bounds
                if 0 <= nx < len(self.minesweeper_map) and 0 <= ny < len(self.minesweeper_map[0]):
                    if self.player_map[nx][ny] == '-':
                        self.sweep(nx, ny)

    # Check if player won (all non-mine cells revealed)
    for i in range(len(self.minesweeper_map)):
        for j in range(len(self.minesweeper_map[0])):
            if self.minesweeper_map[i][j] != 'X' and self.player_map[i][j] == '-':
                return self.player_map

    return True

def calculate_word_frequency(self, words_list):
    """
    计算词汇表中每个单词的词频，并按值降序排序词频字典。
    :param words_list: 一个单词列表的列表
    :return: 前5个词频字典，一个词频字典，键是单词，值是频率
    >>> NLPDataProcessor.calculate_word_frequency([['this', 'is', 'a', 'test'], ['this', 'is', 'another', 'test']])
    {'this': 2, 'is': 2, 'test': 2, 'a': 1, 'another': 1}
    """
    word_freq = {}

    # Count frequency of each word
    for word_list in words_list:
        for word in word_list:
            word_freq[word] = word_freq.get(word, 0) + 1

    # Sort by frequency (descending) and then by word (for stable ordering)
    sorted_word_freq = dict(sorted(word_freq.items(), key=lambda x: (-x[1], x[0])))

    return sorted_word_freq

@staticmethod
def hex_to_decimal(hex_num):
    """
    将一个数字从十六进制格式转换为十进制格式。
    :param hex_num: str, 十六进制数字
    :return: int, 十六进制数字字符串的十进制表示。
    >>> NumberConverter.hex_to_decimal('a5b7')
    42423
    """
    return int(hex_num, 16)

def replace(self, string):
    """
    将输入字符串中的数字字符引用（HTML 实体）替换为相应的 Unicode 字符。
    :param string: str，包含数字字符引用的输入字符串。
    :return: str，输入字符串，其中的数字字符引用已被相应的 Unicode 字符替换。
    >>> unescaper = NumericEntityUnescaper()
    >>> unescaper.replace("&#65;&#66;&#67;")
    'ABC'

    """
    def replace_entity(match):
        entity = match.group(0)
        # 处理十六进制格式 &#xHHHH; 或 &#XHHHH;
        if entity[2] in ('x', 'X'):
            code_point = int(entity[3:-1], 16)
        # 处理十进制格式 &#DDDD;
        else:
            code_point = int(entity[2:-1], 10)

        try:
            return chr(code_point)
        except (ValueError, OverflowError):
            # 如果代码点无效，返回原始实体
            return entity

    # 匹配 &#数字; 或 &#x十六进制; 格式的数字字符引用
    pattern = r'&#[xX]?[0-9a-fA-F]+;'
    return re.sub(pattern, replace_entity, string)

def send(self, info):
    """
    发送包含地址和内容的信息
    :param info: dict，包含地址和内容的信息字典
    :return: 如果成功发送,则返回无;否则,返回一个指示错误消息的字符串
    >>> server.send({"addr":66,"content":"ABC"})
    self.send_struct = {"addr":66,"content":"ABC"}
    """
    try:
        if not isinstance(info, dict):
            return "错误: 参数必须是字典类型"

        if "addr" not in info:
            return "错误: 缺少地址(addr)字段"

        if "content" not in info:
            return "错误: 缺少内容(content)字段"

        self.send_struct = info
        return None
    except Exception as e:
        return f"错误: {str(e)}"

def show(self, type):
    """
    返回指定类型的结构体
    :param type: 字符串，要返回的结构体类型，可以是 'send' 或 'receive'
    :return: 如果 type 等于 'send' 或 'receive'，则返回相应的结构体；否则，返回 False
    >>> server.recv({"addr":88,"content":"abc"})
    >>> server.send({"addr":66,"content":"ABC"})
    >>> server.show("send")
    {"addr":66,"content":"ABC"}
    """
    if type == 'send':
        return self.send_buffer
    elif type == 'receive':
        return self.receive_buffer
    else:
        return False

def add_item(self, item, price, quantity=1):
    """
    将商品信息添加到购物清单中，包括价格和数量。默认数量为1
    :param item: string, 要添加的商品
    :param price: float, 商品的价格
    :param quantity:int, 商品的数量，默认为1
    :return: None
    >>> shoppingcart = ShoppingCart()
    >>> shoppingcart.add_item("apple", 1, 5)
    self.items = {"apple":{"price":1, "quantity":5}}
    """
    if not hasattr(self, 'items'):
        self.items = {}

    self.items[item] = {"price": price, "quantity": quantity}

@staticmethod
def mean(data):
    """
    计算给定列表的平均值。
    :param data: 给定的列表，list。
    :return: 给定列表的平均值，float。
    >>> statistics3 = Statistics3()
    >>> statistics3.mean([1, 2, 3])
    2.0

    """
    if not data:
        return 0.0
    return sum(data) / len(data)

def is_board_full(self):
    """
    检查游戏棋盘是否完全填满。
    :return: bool，表示游戏棋盘是否已满
    >>> ttt.is_board_full()
    False
    """
    for row in self.board:
        for cell in row:
            if cell == ' ' or cell == '':
                return False
    return True

def _generate_cards(self):
    """
    为卡片生成1到9之间的随机数字。
    """
    import random
    return random.randint(1, 9)

import math

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    对 number_dict 中的每个 count 计算 log(total_num+1/count+1) 
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    result = {}
    for key, count in number_dict.items():
        result[key] = math.log((total_num + 1) / (count + 1))
    return result

def add_item(self, item_name, price, quantity):
    """
    将产品添加到自动售货机的库存中。
    :param item_name: 要添加的产品名称，str。
    :param price: 要添加的产品价格，float。
    :param quantity: 要添加的产品数量，int。
    :return: None
    >>> vendingMachine = VendingMachine()
    >>> vendingMachine.add_item('Coke', 1.25, 10)
    >>> vendingMachine.inventory
    {'Coke': {'price': 1.25, 'quantity': 10}}
    """
    if item_name in self.inventory:
        self.inventory[item_name]['quantity'] += quantity
    else:
        self.inventory[item_name] = {'price': price, 'quantity': quantity}

def add_product(self, product_id, name, quantity):
    """
    将产品添加到库存，如果它已经存在于库存中，则增加数量。
    否则，直接将新产品添加到字典中。
    :param product_id: int
    :param name: str, 产品名称
    :param quantity: int, 产品数量
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
    根据 product_id，将数量添加到库存中对应的产品。
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.update_product_quantity(1, -1)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 2}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def text2int(self, textnum):
    """
    将单词字符串转换为相应的整数字符串
    :param textnum: 字符串，要转换的单词字符串
    :return: 字符串，最终转换的整数字符串
    >>> w2n = Words2Numbers()
    >>> w2n.text2int("thirty-two")
    "32"
    """
    ones = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4,
        "five": 5, "six": 6, "seven": 7, "eight": 8, "nine": 9,
        "ten": 10, "eleven": 11, "twelve": 12, "thirteen": 13,
        "fourteen": 14, "fifteen": 15, "sixteen": 16, "seventeen": 17,
        "eighteen": 18, "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    scales = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1000000,
        "billion": 1000000000,
        "trillion": 1000000000000
    }

    textnum = textnum.lower().strip()

    if textnum in ones:
        return str(ones[textnum])

    words = textnum.replace("-", " ").split()

    current = 0
    result = 0

    for word in words:
        if word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            if word == "hundred":
                current *= scales[word]
            else:
                current *= scales[word]
                result += current
                current = 0

    result += current

    return str(result)

def read_zip_file(self):
    """
    获取打开的文件对象
    :return: 如果成功，返回打开的文件对象；否则，返回 None
    >>> zfp = ZipFileProcessor("aaa.zip")
    >>> file = zfp.read_zip_file()
    """
    import zipfile
    import os

    try:
        if hasattr(self, 'zip_file_path') and self.zip_file_path:
            if os.path.exists(self.zip_file_path):
                return zipfile.ZipFile(self.zip_file_path, 'r')
        return None
    except Exception:
        return None
